+async function runSteady(baseUrl) {
+  while (true) {
+    const useHealthy = Math.random() < 0.95;
+    if (useHealthy) {
+      await fireRequest(baseUrl, "/checkout", {
+        userId: "steady-user",
+        amount: 1499,
+        currency: "USD"
+      });
+    } else {
+      await fireRequest(baseUrl, randomFailurePath(), {});
+    }
+    await sleep(500);
+  }
+}
+
+async function runBurst(baseUrl, failureType) {
+  const targetPath = `/fail/${failureType}`;
+  for (let i = 0; i < 20; i += 1) {
+    await fireRequest(baseUrl, targetPath, {});
+    await sleep(500);
+  }
+}
+
+async function main() {
+  const { url, mode } = parseArgs(process.argv.slice(2));
+  if (!url) {
+    throw new Error("Usage: node scripts/load-gen.js --url <base-url> --mode <steady|burst-...>");
+  }
+
+  if (mode === "steady") {
+    await runSteady(url);
+    return;
+  }
+
+  if (!mode.startsWith("burst-")) {
+    throw new Error("Invalid mode. Use steady or burst-code-bug|burst-dependency|burst-saturation");
+  }
+
+  const failureType = mode.replace("burst-", "");
+  await runBurst(url, failureType);
+}
