+import { execSync } from "child_process";
+import fs from "fs";
+
+const DEPLOYMENTS_PATH = "deployments.json";
+
+function git(command) {
+  return execSync(command, { encoding: "utf8" }).trim();
+}
+
+function main() {
+  const commitSha = git("git rev-parse HEAD");
+  const deployedAt = git("git show -s --format=%cI HEAD");
+  const filesChanged = git("git diff-tree --no-commit-id --name-only -r HEAD")
+    .split("\n")
+    .filter(Boolean);
+
+  const parsed = JSON.parse(fs.readFileSync(DEPLOYMENTS_PATH, "utf8"));
+  const deployments = Array.isArray(parsed.deployments) ? parsed.deployments : [];
+
+  deployments.push({ commitSha, deployedAt, filesChanged });
+
+  fs.writeFileSync(
+    DEPLOYMENTS_PATH,
+    JSON.stringify({ deployments }, null, 2) + "\n",
+    "utf8"
+  );
